package com.evernorth.smartemp.controller; import com.evernorth.smartemp.dto.EmployeeDto; import com.evernorth.smartemp.service.EmployeeService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/admin/employees") @RequiredArgsConstructor public class AdminEmployeeController{private final EmployeeService s;@PostMapping public ResponseEntity<EmployeeDto.Response> create(@Valid@RequestBody EmployeeDto.Request r){return ResponseEntity.status(HttpStatus.CREATED).body(s.create(r));}@PutMapping("/{id}")public ResponseEntity<EmployeeDto.Response> update(@PathVariable Long id,@Valid@RequestBody EmployeeDto.Request r){return ResponseEntity.ok(s.update(id,r));}@DeleteMapping("/{id}")public ResponseEntity<Void> delete(@PathVariable Long id){s.delete(id);return ResponseEntity.noContent().build();}}
